declare @c varchar(1024), @accountName nvarchar(1024)
if @@language = 'V' select @accountName = ten_tk from dmtk where tk = @tk else select @accountName = ten_tk2 from dmtk where tk = @tk
select @c = case @nh_theo when '0' then 'nh_vv1' end
if (@c = 'nh_vv1') and (cast(@tt_sx1 as tinyint) + cast(@tt_sx2 as tinyint) + cast(@tt_sx3 as tinyint) <> 0) begin
  set @c = @tt_sx1 + ',' + @tt_sx2 + ',' + @tt_sx3
  set @c = replace(replace(replace(@c, '1', 'nh_vv1'), '2', 'nh_vv2'), '3', 'nh_vv3')
  set @c = replace(replace(replace(@c, '0,', ''), ',0', ''), '0', '')
end
else set @c = ''
select @ngay as date, @tk as tk, @accountName as ten_tk
exec rs_rptJobsBalance @ngay, @tk, @ma_vv_me, @ma_vv, @nh_theo, @nh_vv1, @nh_vv2, @nh_vv3, @c, 'ten_vv, ten_vv2', @loai_ky, @ma_dvcs, @@language, @@userID, @@admin






        /* <flatten type="Javascript"> */
var x = this.getItemValue('tt_sx1'), y = this.getItemValue('tt_sx2'), z = this.getItemValue('tt_sx3');
if ((x == y && x != 0) || (x == z && x != 0) || (y == z && y != 0)){
  this._checked = false;
  $func.hideWait(this.get_id());
  $message.show(String.format($df.getResources(this._language, 'Message.RequiredField'), this.getItem('tt_sx1').field.Label), String.format('$find(\'{0}\').focus(\'{1}\');', this.get_id(), 'tt_sx1'));
}
/* </flatten> */






      &OutlineEntry;
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function onChange$VoucherFilter$Tab(f, e) {f.parentForm.focusWhenTabChanged(['ma_vv_me', 'nh_theo']);}
function active$VoucherFilter$(f) {
  f._tabContainer.add_activeTabChanged(onChange$VoucherFilter$Tab);
  f._tabContainer._loaded = true;
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  var a = ['tk'];
  if (!f._extensions) f.request('GetDefaultValue', 'SetDefaultValue', a);
    else setReferenceValue(f, a);
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, x = f.getItemValue('mau_bc');
      g._alterTitle = [null, [['%s', f.getItemValue('tk'), true], ['%d', f.getItem('ngay').value, true]]];
      g._hiddenFields = [{Fields: 'du_no_nt, du_co_nt', Value: (x == '10')}];
      remove$GridReport$Filter(g);
      break;
    case 'SetDefaultValue':
      f.setItemControlBehavior('ten_tk%l', result[0].Value, null, true);
      if (result[0].Value == '') f.setItemValue('tk', '');
      break;
    default:
      break;
  }
}
function setReferenceValue(f, a) {
  for (var i = 0; i < a.length; i++) {
    var r = $func.findField(a[i], f._fields).ItemReference;
    f.setItemValue(r, $func.findMemvar(r, f._extensions).NewValue);
  }
}
/* </flatten> */







